#!/bin/bash
sed -i 's/<motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="w-full max-w-md">/<motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="w-full max-w-md" onViewportEnter={() => { logTelemetry("auth_gateway_viewed", { initialMode: isLogin ? "login" : "signup" }); }} viewport={{ once: true, amount: 0.2 }}>/g' src/pages/AuthGateway.jsx

sed -i 's/<button type="button" onClick={() => { setIsLogin(!isLogin); setErrorMsg(null); setEmail('\'''\''); setPassword('\'''\''); }} className="text-\[0.65rem\] font-mono text-zinc-500 uppercase tracking-widest hover:text-white transition-colors underline decoration-white\/20 underline-offset-4">/<button type="button" onClick={() => { const nextMode = !isLogin ? "login" : "signup"; setIsLogin(!isLogin); setErrorMsg(null); setEmail('\'''\''); setPassword('\'''\''); logTelemetry("auth_mode_switched", { targetMode: nextMode }); }} className="text-[0.65rem] font-mono text-zinc-500 uppercase tracking-widest hover:text-white transition-colors underline decoration-white\/20 underline-offset-4">/g' src/pages/AuthGateway.jsx
